{
  "sentences": [
    {
      "text": "你好，我想要一杯拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi nátiě, kěyǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 na2tie3, ke3yi3 ma0",
      "translation_en": "Hello, I would like a latte, okay?",
      "translation_ko": "안녕하세요, 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "可以幫我加珍珠嗎？",
      "pinyin": "Kěyǐ bāng wǒ jiā zhēnzhū ma?",
      "pinyin_numeric": "ke3yi3 bang1 wo3 jia1 zhen1zhu1 ma0",
      "translation_en": "Can you add boba for me?",
      "translation_ko": "타피오카 펄을 넣어 주시겠어요?"
    },
    {
      "text": "我要一杯紅茶，半糖，可以嗎？",
      "pinyin": "Wǒ yào yī bēi hóngchá, bàn táng, kěyǐ ma?",
      "pinyin_numeric": "wo3 yao4 yi1 bei1 hong2cha2, ban4 tang2, ke3yi3 ma0",
      "translation_en": "I want a cup of black tea, half sugar, okay?",
      "translation_ko": "홍차 한 잔, 반당으로 주시겠어요?"
    },
    {
      "text": "不好意思，可以給我一個袋子嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ gěi wǒ yī ge dàizi ma?",
      "pinyin_numeric": "bu4 hao3 yi4si, ke3yi3 gei3 wo3 yi1 ge4 dai4zi ma0",
      "translation_en": "Excuse me, can you give me a bag?",
      "translation_ko": "실례합니다, 봉투 하나 주시겠어요?"
    },
    {
      "text": "請問，可以內用嗎？",
      "pinyin": "Qǐngwèn, kěyǐ nèiyòng ma?",
      "pinyin_numeric": "qing3wen4, ke3yi3 nei4yong4 ma0",
      "translation_en": "Excuse me, can I eat here?",
      "translation_ko": "실례합니다, 매장에서 먹을 수 있나요?"
    },
    {
      "text": "可以幫我換成豆漿嗎？",
      "pinyin": "Kěyǐ bāng wǒ huàn chéng dòujiāng ma?",
      "pinyin_numeric": "ke3yi3 bang1 wo3 huan4 cheng2 dou4jiang1 ma0",
      "translation_en": "Can you change it to soy milk for me?",
      "translation_ko": "두유로 바꿔 주시겠어요?"
    },
    {
      "text": "我要一杯綠茶，去冰，可以嗎？",
      "pinyin": "Wǒ yào yī bēi lǜchá, qù bīng, kěyǐ ma?",
      "pinyin_numeric": "wo3 yao4 yi1 bei1 lv4cha2, qu4 bing1, ke3yi3 ma0",
      "translation_en": "I want a cup of green tea, no ice, okay?",
      "translation_ko": "녹차 한 잔, 얼음 빼고 주시겠어요?"
    },
    {
      "text": "麻煩你，可以給我一根吸管嗎？",
      "pinyin": "Máfan nǐ, kěyǐ gěi wǒ yī gēn xīguǎn ma?",
      "pinyin_numeric": "ma2fan ni3, ke3yi3 gei3 wo3 yi1 gen1 xi1guan3 ma0",
      "translation_en": "Excuse me, can you give me a straw?",
      "translation_ko": "번거롭게 해서 죄송합니다만, 빨대 하나 주시겠어요?"
    },
    {
      "text": "可以幫我拍照嗎？",
      "pinyin": "Kěyǐ bāng wǒ pāizhào ma?",
      "pinyin_numeric": "ke3yi3 bang1 wo3 pai1zhao4 ma0",
      "translation_en": "Can you take a picture for me?",
      "translation_ko": "사진을 찍어 주시겠어요?"
    },
    {
      "text": "不好意思，可以再說一次嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ zài shuō yī cì ma?",
      "pinyin_numeric": "bu4 hao3 yi4si, ke3yi3 zai4 shuo1 yi1 ci4 ma0",
      "translation_en": "Excuse me, can you say it again?",
      "translation_ko": "실례합니다, 한 번 더 말씀해 주시겠어요?"
    }
  ]
}
